import { describe, it, expect, vi, beforeEach } from 'vitest';

vi.mock('../src/utils/spawn', () => ({
    spawnPM: vi.fn().mockResolvedValue({ exitCode: 0, stdout: '', stderr: '' }),
}));

vi.mock('../src/detect', () => ({
    detectPackageManager: vi.fn(),
}));

vi.mock('../src/utils/output', () => ({
    isJsonMode: vi.fn().mockReturnValue(false),
    printJSON: vi.fn(),
    printHuman: vi.fn(),
}));

import { remove } from '../src/commands/remove';
import { spawnPM } from '../src/utils/spawn';
import { detectPackageManager } from '../src/detect';

describe('remove', () => {
    beforeEach(() => { vi.clearAllMocks(); });

    it('should generate correct npm uninstall command', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'npm', version: '10.0.0', reason: 'default' });
        await remove(['lodash'], {});
        expect(spawnPM).toHaveBeenCalledWith('npm', ['uninstall', 'lodash'], expect.anything());
    });

    it('should generate correct yarn remove command', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'yarn', version: '1.22.0', reason: 'lockfile', lockfile: 'yarn.lock' });
        await remove(['lodash'], {});
        expect(spawnPM).toHaveBeenCalledWith('yarn', ['remove', 'lodash'], expect.anything());
    });

    it('should generate correct pnpm remove command', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'pnpm', version: '8.0.0', reason: 'default' });
        await remove(['lodash'], {});
        expect(spawnPM).toHaveBeenCalledWith('pnpm', ['remove', 'lodash'], expect.anything());
    });

    it('should generate correct bun remove command', async () => {
        vi.mocked(detectPackageManager).mockReturnValue({ pm: 'bun', version: '1.0.0', reason: 'default' });
        await remove(['lodash'], {});
        expect(spawnPM).toHaveBeenCalledWith('bun', ['remove', 'lodash'], expect.anything());
    });

    it('should error when no packages specified', async () => {
        const result = await remove([], {});
        expect(result.exitCode).toBe(1);
        expect(spawnPM).not.toHaveBeenCalled();
    });
});
